1	export type Cell = [number, number];
2	
3	const key = (c: Cell): string => `${c[0]},${c[1]}`;
4	
5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const result: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      result.push([x + dx, y + dy]);
11	    }
12	  }
13	  return result;
14	};
15	
16	export function nextGeneration(cells: readonly Cell[]): Cell[] {
17	  const alive = new Set(cells.map(key));
18	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
19	  for (const cell of cells) {
20	    for (const n of neighborsOf(cell)) {
21	      const k = key(n);
22	      const entry = neighborCounts.get(k);
23	      if (entry) entry.count++;
24	      else neighborCounts.set(k, { cell: n, count: 1 });
25	    }
26	  }
27	  return Array.from(neighborCounts.entries())
28	    .filter(([k, { count }]) => count === 3 || (count === 2 && alive.has(k)))
29	    .map(([, { cell }]) => cell);
30	}
31

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("live cell with 4 neighbors dies from overpopulation (rule 3 center cell)", () => {
21	    // Gen 0: top row + center + bottom row → center (1,1) has 4 neighbors → dies
22	    const input: Cell[] = [
23	      [0, 0], [1, 0], [2, 0],
24	      [1, 1],
25	      [0, 2], [1, 2], [2, 2],
26	    ];
27	    const result = nextGeneration(input);
28	    expect(result).not.toContainEqual([1, 1]);
29	  });
30	  it("dead cell with exactly 3 neighbors becomes alive (rule 4 reproduction)", () => {
31	    // Gen 0: (0,0), (1,0), (0,1). Dead cell (1,1) has 3 live neighbors → born
32	    const input: Cell[] = [[0, 0], [1, 0], [0, 1]];
33	    const result = nextGeneration(input);
34	    expect(result).toContainEqual([1, 1]);
35	  });
36	  it("rule 2 survival example — live cell with 2 neighbors survives", () => {
37	    // Three-in-a-row: center cell (1,0) has 2 live neighbors → survives
38	    const input: Cell[] = [[0, 0], [1, 0], [2, 0]];
39	    const result = nextGeneration(input);
40	    expect(result).toContainEqual([1, 0]);
41	  });
42	  it("blinker oscillates from vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
43	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
44	    const result = nextGeneration(vertical);
45	    expect(result).toHaveLength(3);
46	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]] as Cell[]));
47	  });
48	});
